queries.sphinxql:
create table test1 ( title text, tag integer );
insert into test1 values (1, 'word form', 11);
select * from test1 where match ( 'wordform' );

alter table test1 wordforms = '/wordforms.txt';

insert into test1 values (2, 'word form', 11);
select * from test1 where match ( 'wordform' );


CREATE TABLE test11 (title TEXT, category INT) min_infix_len='4';
CREATE TABLE test12 LIKE test11;
ALTER TABLE test11 ignore_chars='.';
SHOW INDEX test11 SETTINGS;
SHOW INDEX test12 SETTINGS;

drop table test1;
drop table test11;
drop table test12;

CREATE TABLE test1 (title text) rt_mem_limit='2G';
CREATE TABLE test2 LIKE test1;
SHOW CREATE TABLE test1;
SHOW CREATE TABLE test2;

ALTER TABLE test1 rt_mem_limit='1G';
SHOW CREATE TABLE test1;

drop table test1;
drop table test2;

ALTER TABLE test1 RECONFIGURE;

create table test3 ( title text, tag integer ) exceptions='/exc.txt' wordforms = '/wordforms1.txt' stopwords = '/stop.txt';
insert into test3 values (1, 'word form', 11);
call keywords('a b c1 c d', 'test3');
alter table test3 exceptions = '';
insert into test3 values (2, 'word form', 11);
alter table test3 wordforms = '';
insert into test3 values (3, 'word form', 11);
alter table test3 stopwords = '';
insert into test3 values (4, 'word form', 11);
call keywords('a b c1 c d', 'test3');
drop table test3;

create table test4 ( title text, tag integer ) exceptions='/exc.txt' wordforms = '/wordforms1.txt' stopwords = '/stop.txt';
insert into test4 values (1, 'a b c1 c d', 11);
alter table test4 exceptions = '' wordforms = '' stopwords = '';
insert into test4 values (2, 'a b c1 c d', 11);
select * from test4 where match ('a b c1 c d') order by id asc;
drop table test4;


create table test4 ( title text, tag integer );


show table test4 chunk 15 settings;

drop table test4;

create table test5 ( title text ) dict='keywords' bigram_index='all';
insert into test5 values (1, 'xt 806');

alter table test5 bigram_delimiter='none';
show create table test5;

insert into test5 values (2, 'xt 806');
select * from test5 where match('xt806') order by id asc;

alter table test5 bigram_index='second_numeric';
show create table test5;

insert into test5 values (3, 'xt 806');
insert into test5 values (4, 'xt rt9600');
insert into test5 values (5, 'xt v2');
select * from test5 where match('xt806') order by id asc;
select * from test5 where match('xtrt9600') order by id asc;
select * from test5 where match('xtv2') order by id asc;

alter table test5 bigram_index='second_has_digit';
show create table test5;

insert into test5 values (6, 'xt 806');
insert into test5 values (7, 'xt rt9600');
insert into test5 values (8, 'xt v2');
insert into test5 values (9, 'xt abc');
select * from test5 where match('xt806') order by id asc;
select * from test5 where match('xtrt9600') order by id asc;
select * from test5 where match('xtv2') order by id asc;
select * from test5 where match('xtabc') order by id asc;

alter table test5 bigram_freq_words='the, a';

alter table test5 bigram_index='first_freq' bigram_freq_words='the, a';
